/**
 * NullRecords Unified Navigation
 * Include on every page:
 *   <script src="/nav-data.js"></script>
 *   <script src="/shared-nav.js" defer></script>
 *
 * nav-data.js is generated by Forgeweb from the navigation database.
 * Edit navigation via the Forgeweb admin Navigation Manager.
 */
(function () {
  'use strict';

  // Read config from Forgeweb-generated nav-data.js, fall back to defaults
  var cfg = window.NR_NAV_CONFIG || {};
  var logoSrc = cfg.logo || '/assets/logos/logo.png';
  var cfgItems = cfg.items || [
    { title: 'Home', url: '/' },
    { title: 'Store', url: '/store/' },
    { title: 'News', url: '/news/' },
    { title: 'About', url: '/about.html' },
    { title: 'Contact', url: '/contact.html' },
  ];

  // Normalise to internal format
  var links = cfgItems.map(function (item) {
    return { href: item.url, label: item.title, newTab: item.open_new_tab };
  });

  // Detect current page for active link highlighting
  const path = window.location.pathname;
  function isActive(href) {
    if (href === '/' || href === '/index.html') return path === '/' || path === '/index.html' || path.endsWith('/docs/index.html');
    return path.startsWith(href.replace(/index\.html$/, ''));
  }

  function esc(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

  function navLink(l, mobile) {
    const active = isActive(l.href);
    const target = l.newTab ? ' target="_blank" rel="noopener"' : '';
    if (mobile) {
      return `<a href="${esc(l.href)}"${target} class="nr-nav-link${active ? ' nr-active' : ''} block px-3 py-2">${esc(l.label)}</a>`;
    }
    return `<a href="${esc(l.href)}"${target} class="nr-nav-link${active ? ' nr-active' : ''}">${esc(l.label)}</a>`;
  }

  const navHTML = `
<nav class="nr-navbar" id="nr-navbar">
  <div class="nr-nav-inner">
    <a href="/" class="nr-logo-link">
      <img src="${esc(logoSrc)}" alt="NullRecords" class="nr-logo-img" />
    </a>
    <div class="nr-nav-links" id="nr-nav-links">
      ${links.map(l => navLink(l, false)).join('\n      ')}
    </div>
    <button class="nr-hamburger" id="nr-hamburger" aria-label="Toggle menu">
      <svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16"/>
      </svg>
    </button>
  </div>
  <div class="nr-mobile-menu" id="nr-mobile-menu">
    ${links.map(l => navLink(l, true)).join('\n    ')}
  </div>
</nav>`;

  const style = document.createElement('style');
  style.textContent = `
/* NullRecords Unified Nav */
.nr-navbar {
  position: sticky; top: 0; z-index: 9999;
  background: rgba(10,10,10,0.92);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid #333;
  font-family: 'JetBrains Mono', 'Consolas', monospace;
}
.nr-nav-inner {
  max-width: 1100px; margin: 0 auto;
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 1rem; height: 60px;
}
.nr-logo-link { display: flex; align-items: center; text-decoration: none; }
.nr-logo-img { height: 44px; width: auto; }
.nr-nav-links { display: flex; gap: 0.25rem; align-items: center; }
.nr-nav-link {
  color: #e0e7ff; font-size: 0.8rem; padding: 6px 14px;
  text-decoration: none; transition: color 0.2s, text-shadow 0.2s;
  font-family: 'Press Start 2P', 'JetBrains Mono', monospace; font-size: 0.55rem;
  letter-spacing: 0.5px; text-transform: uppercase;
}
.nr-nav-link:hover { color: #00ffff; text-shadow: 0 0 8px #00ffff; }
.nr-nav-link.nr-active { color: #ff5758; border-bottom: 2px solid #ff5758; }
.nr-hamburger {
  display: none; background: none; border: none; color: #e0e7ff; cursor: pointer; padding: 4px;
}
.nr-hamburger:hover { color: #00ffff; }
.nr-mobile-menu { display: none; padding: 0.5rem 1rem 1rem; background: #0a0a0a; border-top: 1px solid #333; }

@media (max-width: 768px) {
  .nr-nav-links { display: none; }
  .nr-hamburger { display: block; }
  .nr-mobile-menu.nr-open { display: block; }
}
`;
  document.head.appendChild(style);

  // Remove any existing header/old nav at the top of body
  function injectNav() {
    // Create a container for the nav
    const container = document.createElement('div');
    container.innerHTML = navHTML.trim();
    const navEl = container.firstChild;

    // Find and remove old store header or any <header> at top of body
    const oldHeader = document.querySelector('body > header');
    if (oldHeader) oldHeader.remove();

    // Find old nav that's a direct child of body (but not ours)
    const oldNavs = document.querySelectorAll('body > nav:not(#nr-navbar)');
    oldNavs.forEach(n => n.remove());

    // Insert our nav at the very top
    document.body.insertBefore(navEl, document.body.firstChild);

    // Hamburger toggle
    const hamburger = document.getElementById('nr-hamburger');
    const mobileMenu = document.getElementById('nr-mobile-menu');
    if (hamburger && mobileMenu) {
      hamburger.addEventListener('click', function () {
        mobileMenu.classList.toggle('nr-open');
      });
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', injectNav);
  } else {
    injectNav();
  }
})();
